def solve_b99e7126(grid):
    grid = [row[:] for row in grid]
    H, W = len(grid), len(grid[0])
    tile_h = tile_w = 4
    num_tr = H // tile_h
    num_tc = W // tile_w
    tiles = {}
    for tr in range(num_tr):
        for tc in range(num_tc):
            tile = tuple(tuple(grid[tr*4+r][tc*4+c] for c in range(4)) for r in range(4))
            tiles[(tr,tc)] = tile
    base = Counter(tiles.values()).most_common(1)[0][0]
    mod_tile = None
    in_pos = []
    for (tr,tc),v in tiles.items():
        if v != base:
            mod_tile = v
            in_pos.append((tr,tc))
    if not mod_tile:
        return grid
    new_color_count = Counter()
    for r in range(1,4):
        for c in range(1,4):
            if mod_tile[r][c] != base[r][c]:
                new_color_count[mod_tile[r][c]] += 1
    dominant_color = new_color_count.most_common(1)[0][0]
    pattern = set()
    for r in range(3):
        for c in range(3):
            if mod_tile[r+1][c+1] == dominant_color:
                pattern.add((r, c))
    found_offset = None
    for off_r in range(-num_tr, num_tr):
        for off_c in range(-num_tc, num_tc):
            shifted = set((r+off_r, c+off_c) for r,c in pattern)
            if all(p in shifted for p in in_pos):
                found_offset = (off_r, off_c)
                break
        if found_offset:
            break
    for r, c in pattern:
        tr, tc = r + found_offset[0], c + found_offset[1]
        if 0 <= tr < num_tr and 0 <= tc < num_tc:
            for lr in range(4):
                for lc in range(4):
                    grid[tr*4+lr][tc*4+lc] = mod_tile[lr][lc]
    return grid

