def solve_b10624e5(grid):
    grid = [row[:] for row in grid]
    H, W = len(grid), len(grid[0])
    bg = 4
    div_r = div_c = None
    for r in range(H):
        if all(grid[r][c] == 1 for c in range(W)):
            div_r = r
    for c in range(W):
        if all(grid[r][c] == 1 for r in range(H)):
            div_c = c
    quads = {
        'TL': (range(0, div_r), range(0, div_c)),
        'TR': (range(0, div_r), range(div_c+1, W)),
        'BL': (range(div_r+1, H), range(0, div_c)),
        'BR': (range(div_r+1, H), range(div_c+1, W))
    }
    template_quad = None
    for qname, (rr, cr) in quads.items():
        colors = set()
        for r in rr:
            for c in cr:
                if grid[r][c] != bg:
                    colors.add(grid[r][c])
        if len(colors) > 1:
            template_quad = qname
            break
    if not template_quad:
        return grid
    rr, cr = quads[template_quad]
    color_blocks = defaultdict(list)
    for r in rr:
        for c in cr:
            if grid[r][c] != bg:
                color_blocks[grid[r][c]].append((r,c))
    t2 = color_blocks[2]
    t2_min_r, t2_max_r = min(r for r,c in t2), max(r for r,c in t2)
    t2_min_c, t2_max_c = min(c for r,c in t2), max(c for r,c in t2)
    t2_h = t2_max_r - t2_min_r + 1
    t2_w = t2_max_c - t2_min_c + 1
    other_blocks = {}
    for color, pxls in color_blocks.items():
        if color == 2:
            continue
        bb_min_r = min(r for r,c in pxls)
        bb_max_r = max(r for r,c in pxls)
        bb_min_c = min(c for r,c in pxls)
        bb_max_c = max(c for r,c in pxls)
        bb_h = bb_max_r - bb_min_r + 1
        bb_w = bb_max_c - bb_min_c + 1
        rel_r = bb_min_r - t2_min_r
        rel_c = bb_min_c - t2_min_c
        shape = set()
        for r,c in pxls:
            shape.add((r - bb_min_r, c - bb_min_c))
        other_blocks[color] = {
            'rel_r': rel_r, 'rel_c': rel_c,
            'h': bb_h, 'w': bb_w,
            'shape': shape
        }
    for qname, (qrr, qcr) in quads.items():
        if qname == template_quad:
            continue
        q2 = [(r,c) for r in qrr for c in qcr if grid[r][c] == 2]
        if not q2:
            continue
        q2_min_r = min(r for r,c in q2)
        q2_max_r = max(r for r,c in q2)
        q2_min_c = min(c for r,c in q2)
        q2_max_c = max(c for r,c in q2)
        q2_h = q2_max_r - q2_min_r + 1
        q2_w = q2_max_c - q2_min_c + 1
        scale_r = q2_h / t2_h
        scale_c = q2_w / t2_w
        flip_h = flip_v = False
        if template_quad == 'TL':
            if qname == 'TR': flip_h = True
            elif qname == 'BL': flip_v = True
            elif qname == 'BR': flip_h = True; flip_v = True
        elif template_quad == 'TR':
            if qname == 'TL': flip_h = True
            elif qname == 'BL': flip_h = True; flip_v = True
            elif qname == 'BR': flip_v = True
        elif template_quad == 'BL':
            if qname == 'TL': flip_v = True
            elif qname == 'TR': flip_h = True; flip_v = True
            elif qname == 'BR': flip_h = True
        elif template_quad == 'BR':
            if qname == 'TL': flip_h = True; flip_v = True
            elif qname == 'TR': flip_v = True
            elif qname == 'BL': flip_h = True
        for color, info in other_blocks.items():
            rel_r = info['rel_r']
            rel_c = info['rel_c']
            bh = info['h']
            bw = info['w']
            new_rel_r = rel_r * scale_r
            new_rel_c = rel_c * scale_c
            new_bh = round(bh * scale_r)
            new_bw = round(bw * scale_c)
            if flip_h:
                new_rel_c = q2_w - new_rel_c - new_bw
            if flip_v:
                new_rel_r = q2_h - new_rel_r - new_bh
            block_r = round(q2_min_r + new_rel_r)
            block_c = round(q2_min_c + new_rel_c)
            for nr in range(new_bh):
                for nc in range(new_bw):
                    orig_r = int(nr / scale_r)
                    orig_c = int(nc / scale_c)
                    if (orig_r, orig_c) in info['shape']:
                        pr = block_r + nr
                        pc = block_c + nc
                        if 0 <= pr < H and 0 <= pc < W:
                            grid[pr][pc] = color
    return grid
